vertical_spacing_when_wrapping.implementation_example:
// Example: Narrow grid with tiles that wrap
<Grid narrow className="tile-grid">
  {/* Tiles wrap to new rows on smaller screens */}
  <Column sm={4} md={4} lg={4}>
    <Tile>Tile 1</Tile>
  </Column>
  <Column sm={4} md={4} lg={4}>
    <Tile>Tile 2</Tile>
  </Column>
  <Column sm={4} md={4} lg={4}>
    <Tile>Tile 3</Tile>
  </Column>
  <Column sm={4} md={4} lg={4}>
    <Tile>Tile 4</Tile>
  </Column>
</Grid>

// SCSS: Match vertical spacing to narrow grid's 16px gutter using row-gap
.tile-grid {
  row-gap: $spacing-05; // 16px vertical spacing matches narrow grid gutter
}

// For default grid (32px gutter)
.default-grid {
  row-gap: $spacing-07; // 32px vertical spacing
}

// For condensed grid (0px gutter)
.condensed-grid {
  row-gap: 0; // No vertical spacing
}
